class ReportEngine:
    """Base engine for generating formatted output."""

    def __init__(self):
        self._format_name = "base"

    def render(self, datum):
        """Process input into formatted output."""
        title = datum.get("title", "Untitled")
        return f"[{self._format_name}] {title}"

    def supports_format(self, format_name):
        """Check if this engine supports the given format."""
        return self._format_name == format_name

