from .engine import ReportEngine


class CsvEngine(ReportEngine):
    """Engine that outputs CSV rows."""

    def __init__(self):
        super().__init__()
        self._format_name = "csv"

    def render(self, datum):
        """Convert input to a CSV row."""
        return ",".join(str(v) for v in datum.values())

