from .engine import ReportEngine


class JsonEngine(ReportEngine):
    """Engine that outputs JSON strings."""

    def __init__(self):
        super().__init__()
        self._format_name = "json"

    def render(self, datum):
        """Convert input to a JSON string."""
        return json.dumps(datum, sort_keys=True)

